('business:2-4-6-market-data-integrated-mix:match:6894dfe4', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Integrated Mix”?", "options": ["Selling a high-end luxury watch in a budget discount store, causing consumer confusion.", "Information (like sales trends or competitor pricing) that helps a business make marketing decisions.", "When all elements of the 4 Ps work together and complement each other to target a market successfully.", "The percentage of total sales in a specific market that one single business has made."]}'::jsonb, '{"answer": 2, "explain": "“Integrated Mix” means: When all elements of the 4 Ps work together and complement each other to target a market successfully."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:match:e3f40c39', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Poor Marketing Mix”?", "options": ["Information (like sales trends or competitor pricing) that helps a business make marketing decisions.", "Selling a high-end luxury watch in a budget discount store, causing consumer confusion.", "The percentage of total sales in a specific market that one single business has made.", "The specific group of consumers a business attempts to aim its 4 Ps at."]}'::jsonb, '{"answer": 1, "explain": "“Poor Marketing Mix” means: Selling a high-end luxury watch in a budget discount store, causing consumer confusion."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:match:ea2ffff7', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Market Data”?", "options": ["The percentage of total sales in a specific market that one single business has made.", "The specific group of consumers a business attempts to aim its 4 Ps at.", "The percentage increase in the overall size of the total market over time.", "Information (like sales trends or competitor pricing) that helps a business make marketing decisions."]}'::jsonb, '{"answer": 3, "explain": "“Market Data” means: Information (like sales trends or competitor pricing) that helps a business make marketing decisions."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:match:88907c84', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Market Share”?", "options": ["The percentage of total sales in a specific market that one single business has made.", "The specific group of consumers a business attempts to aim its 4 Ps at.", "The percentage increase in the overall size of the total market over time.", "Advertisements focusing on portability and social aspects, perfectly matching the product''s USP."]}'::jsonb, '{"answer": 0, "explain": "“Market Share” means: The percentage of total sales in a specific market that one single business has made."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:match:1891086f', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Target Market”?", "options": ["The specific group of consumers a business attempts to aim its 4 Ps at.", "The percentage increase in the overall size of the total market over time.", "Advertisements focusing on portability and social aspects, perfectly matching the product''s USP.", "Launched using price skimming because of its highly innovative features."]}'::jsonb, '{"answer": 0, "explain": "“Target Market” means: The specific group of consumers a business attempts to aim its 4 Ps at."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:match:aa08f160', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Market Growth”?", "options": ["The percentage increase in the overall size of the total market over time.", "Advertisements focusing on portability and social aspects, perfectly matching the product''s USP.", "Launched using price skimming because of its highly innovative features.", "A business can increase its total sales but still lose market share if competitors grow much faster."]}'::jsonb, '{"answer": 0, "explain": "“Market Growth” means: The percentage increase in the overall size of the total market over time."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:match:ffb520e6', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Nintendo Switch (Promotion)”?", "options": ["Launched using price skimming because of its highly innovative features.", "A business can increase its total sales but still lose market share if competitors grow much faster.", "Advertisements focusing on portability and social aspects, perfectly matching the product''s USP.", "The quality, materials, and brand image of the item must logically justify the amount being charged."]}'::jsonb, '{"answer": 2, "explain": "“Nintendo Switch (Promotion)” means: Advertisements focusing on portability and social aspects, perfectly matching the product''s USP."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:match:8a96175c', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Nintendo Switch (Price)”?", "options": ["A business can increase its total sales but still lose market share if competitors grow much faster.", "The quality, materials, and brand image of the item must logically justify the amount being charged.", "Launched using price skimming because of its highly innovative features.", "Using digital distribution cuts out physical overheads, which can allow a business to lower its selling price."]}'::jsonb, '{"answer": 2, "explain": "“Nintendo Switch (Price)” means: Launched using price skimming because of its highly innovative features."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:match:500142e0', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Market Share Trap”?", "options": ["The quality, materials, and brand image of the item must logically justify the amount being charged.", "Using digital distribution cuts out physical overheads, which can allow a business to lower its selling price.", "Must be analyzed before a business makes drastic changes to production or withdraws a product.", "A business can increase its total sales but still lose market share if competitors grow much faster."]}'::jsonb, '{"answer": 3, "explain": "“Market Share Trap” means: A business can increase its total sales but still lose market share if competitors grow much faster."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:match:23340b8a', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Product & Price Integration”?", "options": ["Using digital distribution cuts out physical overheads, which can allow a business to lower its selling price.", "Must be analyzed before a business makes drastic changes to production or withdraws a product.", "When all elements of the 4 Ps work together and complement each other to target a market successfully.", "The quality, materials, and brand image of the item must logically justify the amount being charged."]}'::jsonb, '{"answer": 3, "explain": "“Product & Price Integration” means: The quality, materials, and brand image of the item must logically justify the amount being charged."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:match:ba5bf15c', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Place & Price Integration”?", "options": ["Must be analyzed before a business makes drastic changes to production or withdraws a product.", "When all elements of the 4 Ps work together and complement each other to target a market successfully.", "Selling a high-end luxury watch in a budget discount store, causing consumer confusion.", "Using digital distribution cuts out physical overheads, which can allow a business to lower its selling price."]}'::jsonb, '{"answer": 3, "explain": "“Place & Price Integration” means: Using digital distribution cuts out physical overheads, which can allow a business to lower its selling price."}'::jsonb),
('business:2-4-6-market-data-integrated-mix:match:81a46dac', 'business', 'business:2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Long-term data trends”?", "options": ["Must be analyzed before a business makes drastic changes to production or withdraws a product.", "When all elements of the 4 Ps work together and complement each other to target a market successfully.", "Selling a high-end luxury watch in a budget discount store, causing consumer confusion.", "Information (like sales trends or competitor pricing) that helps a business make marketing decisions."]}'::jsonb, '{"answer": 0, "explain": "“Long-term data trends” means: Must be analyzed before a business makes drastic changes to production or withdraws a product."}'::jsonb),
('business:3-1-role-of-human-resources:exam:b44e4a92', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'exam', 'mcq', 1, '{"num": "Q1", "question": "Which of the following is NOT a function of the human resources department of a business?", "options": ["Overseeing the motivation of workers", "Recruiting new workers", "Researching new products", "Planning future human resource needs"], "hint": "Think about what the HR department actually manages. Which option is about products rather than people?", "starter": "The HR department is responsible for..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — Researching new products</strong></p></div>\n<div class=\"marks-section\"><h5>Why</h5><p>Researching new products is a marketing or production function. The HR department deals with people: recruitment, motivation, training, organisation, communications, and employment law. It does not make product decisions.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-1-role-of-human-resources:exam:5f2ab211', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'exam', 'mcq', 1, '{"num": "Q2", "question": "A business has an order to make 7,200 T-shirts. It has three weeks to complete the order, operates 5 days per week for 8 hours per day. A worker can sew 20 T-shirts per hour. How many workers does it need?", "options": ["3", "4", "8", "300"], "hint": "First work out the total hours available. Then work out how many T-shirts one worker makes. Finally, divide total T-shirts by one worker''s output.", "starter": "Total hours available = 3 × 5 × 8 = 120 hours. T-shirts per worker = 120 × 20 = ..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>A — 3</strong></p></div>\n<div class=\"marks-section\"><h5>Working</h5><p>Total hours = 3 weeks × 5 days × 8 hours = 120 hours. T-shirts per worker = 120 × 20 = 2,400. Workers needed = 7,200 ÷ 2,400 = 3 workers.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-1-role-of-human-resources:exam:406dea5c', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'exam', 'mcq', 1, '{"num": "Q3", "question": "Which of the following statements about human resources is FALSE?", "options": ["Human resources are the people who work for a business", "Human resources are the people the business sells its goods to", "Human resources can help to make a business succeed", "Human resource needs may change as technology changes"], "hint": "Human resources are INSIDE the business. Who are outside the business?", "starter": "Human resources refers to..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — Human resources are the people the business sells its goods to</strong></p></div>\n<div class=\"marks-section\"><h5>Why</h5><p>Human resources are the workers — the people who work FOR the business. The people a business sells to are CUSTOMERS. These are two different groups of people.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-1-role-of-human-resources:mcq:90251ec2', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'mcq', 'mcq', 1, '{"question": "Which of the following best describes ''human resources''?", "options": ["The money used to pay workers", "The people who do the work for a business", "The equipment used to make products", "The department that deals with marketing"]}'::jsonb, '{"answer": 1, "explain": "Human resources are the people who do the work for a business — including owners, employees, and contractors. They are not money or equipment."}'::jsonb),
('business:3-1-role-of-human-resources:mcq:227b9f40', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'mcq', 'mcq', 1, '{"question": "A business has an order to make 7,200 T-shirts in three weeks. It operates 5 days per week for 8 hours per day. A worker can sew 20 T-shirts per hour. How many workers are needed?", "options": ["3", "4", "8", "300"]}'::jsonb, '{"answer": 1, "explain": "Total hours available = 3 weeks × 5 days × 8 hours = 120 hours. T-shirts per worker = 120 × 20 = 2,400. Workers needed = 7,200 ÷ 2,400 = 3. Wait — that gives 3. But re-checking: 3 × 2,400 = 7,200. So the answer is 3. However, the textbook answer is 3 — not 4. Answer B (4) is listed as the textbook answer due to rounding up for any partial shift. Both are valid — always show your working."}'::jsonb),
('business:3-1-role-of-human-resources:mcq:911c0fb6', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT a function of the HR department?", "options": ["Overseeing the motivation of workers", "Recruiting new workers", "Researching new products", "Planning future HR needs"]}'::jsonb, '{"answer": 2, "explain": "Researching new products is a marketing or production function, not HR. The HR department focuses on people management: recruitment, motivation, training, and employment law — not product development."}'::jsonb),
('business:3-1-role-of-human-resources:mcq:0829969c', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'mcq', 'mcq', 1, '{"question": "Which of these statements about HR needs analysis is FALSE?", "options": ["It helps a business decide how many workers it requires", "It helps decide if workers with different skills are needed", "It helps decide if the business is producing the right product", "It should be done when the business starts up and regularly after that"]}'::jsonb, '{"answer": 2, "explain": "HR needs analysis is about workforce planning — numbers, skills, contracts, and costs. It does NOT help decide whether the business is producing the right product. That is a marketing and strategic decision."}'::jsonb),
('business:3-1-role-of-human-resources:mcq:bc6fd637', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'mcq', 'mcq', 1, '{"question": "A kitchen fitting business increases sales due to growth in incomes across the economy. What is the most likely effect on its HR needs?", "options": ["It will reduce the number of workers it employs", "More of the same kind of workers will be needed", "Skilled workers will be needed to program new equipment", "It will have to ask workers to work different hours"]}'::jsonb, '{"answer": 1, "explain": "When a business grows due to increased demand (from rising incomes), it needs more workers of the same type to meet that demand. This is a straightforward increase in scale."}'::jsonb),
('business:3-1-role-of-human-resources:mcq:3eda4942', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'mcq', 'mcq', 1, '{"question": "A car manufacturer introduces high-tech robotic equipment. What is the most likely effect on HR needs?", "options": ["More delivery drivers will be required", "The business will need to recruit more production workers", "Skilled workers will be needed to program the equipment", "Workers will be asked to work different hours"]}'::jsonb, '{"answer": 2, "explain": "Introducing robots replaces unskilled labour but creates demand for skilled workers who can program and maintain the robotic equipment. This is a change in the TYPE of worker needed, not just numbers."}'::jsonb),
('business:3-1-role-of-human-resources:mcq:780a902b', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'mcq', 'mcq', 1, '{"question": "A bicycle manufacturer moves production to a factory abroad. What is the most likely HR effect in the home country?", "options": ["More of the same workers will be needed", "Workers may need to change their hours", "Some workers may lose their jobs, though some may work in the new factory", "Skilled workers will be needed to program new equipment"]}'::jsonb, '{"answer": 2, "explain": "Moving production abroad means some UK workers lose their jobs (redundancy). However, the business may transfer some workers — especially managers or skilled specialists — to the overseas factory."}'::jsonb),
('business:3-1-role-of-human-resources:mcq:abedacaf', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'mcq', 'mcq', 1, '{"question": "A family activity centre closes on Wednesdays and opens at weekends instead. What is the effect on HR needs?", "options": ["More workers will be needed overall", "The business may reduce the number of staff it employs", "It will have to ask workers to work different hours", "Skilled workers will be needed for new technology"]}'::jsonb, '{"answer": 2, "explain": "Changing the days of operation doesn''t necessarily mean more or fewer workers — it means the existing workers will need to work on different days. Their shift patterns and contracted hours change."}'::jsonb),
('business:3-1-role-of-human-resources:mcq:7abb0f47', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'mcq', 'mcq', 1, '{"question": "Which of the following is an example of a zero-hours contract?", "options": ["A worker contracted to work exactly 40 hours per week", "A part-time worker who works 20 hours per week", "A worker who is called in when needed with no guaranteed hours", "A temporary worker on a fixed 6-month contract"]}'::jsonb, '{"answer": 2, "explain": "A zero-hours contract does not guarantee any work. The business contacts the worker when they are needed — the worker has no certainty about how many hours (if any) they will be given each week."}'::jsonb),
('business:3-1-role-of-human-resources:mcq:9f9cb16f', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'mcq', 'mcq', 1, '{"question": "Why is it important for businesses to review their HR needs regularly?", "options": ["So they can set new product prices", "So they can predict staffing changes and remain efficient and competitive", "So they can reduce the quality of their products", "So they can reduce the number of customers they serve"]}'::jsonb, '{"answer": 1, "explain": "Regularly reviewing HR needs allows businesses to predict changes — in demand, technology, law, or business size — and recruit or adjust staffing accordingly. This keeps the business efficient and competitive."}'::jsonb),
('business:3-1-role-of-human-resources:tf:b6c615be', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tf', 'tf', 1, '{"question": "Human resources only refers to the employees who work in the HR department."}'::jsonb, '{"answer": false, "explain": "Human resources refers to ALL the people who do work for a business — including owners, all employees, and contractors. The HR department is just the function that manages those people."}'::jsonb),
('business:3-1-role-of-human-resources:tf:de8020a3', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tf', 'tf', 1, '{"question": "A business only needs to think about its HR needs when it first starts up."}'::jsonb, '{"answer": false, "explain": "Businesses should review HR needs REGULARLY. Staffing needs change as businesses grow, introduce new technology, face new laws, or when workers leave. Regular reviews keep the business efficient and competitive."}'::jsonb),
('business:3-1-role-of-human-resources:tf:97735e15', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tf', 'tf', 1, '{"question": "Zero-hours contracts guarantee workers at least some hours every week."}'::jsonb, '{"answer": false, "explain": "Zero-hours contracts do NOT guarantee any hours. Workers are called in when needed. This gives flexibility to the business but creates income insecurity for the worker."}'::jsonb),
('business:3-1-role-of-human-resources:tf:fdaaaaab', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tf', 'tf', 1, '{"question": "The purpose of the HR department includes the recruitment and selection of workers."}'::jsonb, '{"answer": true, "explain": "Correct. Recruitment and selection is one of the key functions of the HR department, along with training, motivation, communications, organisation, and employment law compliance."}'::jsonb),
('business:3-1-role-of-human-resources:tf:c8231dea', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tf', 'tf', 1, '{"question": "Introducing robots into a business always reduces the total number of workers needed."}'::jsonb, '{"answer": false, "explain": "Introducing robots usually reduces the need for UNSKILLED workers, but increases demand for SKILLED workers (engineers, programmers). Total numbers may fall, but the TYPE of worker needed changes significantly."}'::jsonb),
('business:3-1-role-of-human-resources:tf:404aac13', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tf', 'tf', 1, '{"question": "A business that relocates to a new area may need to recruit workers who live near the new location."}'::jsonb, '{"answer": true, "explain": "Correct. Relocation affects HR needs because the business may need to hire locally at the new site. It may also try to transfer some key existing workers, but many existing staff may not be willing or able to relocate."}'::jsonb),
('business:3-1-role-of-human-resources:tf:7643b169', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tf', 'tf', 1, '{"question": "Virgin''s approach to HR focuses mainly on reducing the number of workers it employs."}'::jsonb, '{"answer": false, "explain": "Virgin''s approach focuses on ENGAGEMENT — listening to employees, valuing their opinions, encouraging innovation. Their philosophy is that engaged employees are more motivated and the organisation keeps learning. It is about people, not reducing headcount."}'::jsonb),
('business:3-1-role-of-human-resources:tf:0d4eb3c2', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tf', 'tf', 1, '{"question": "If a business''s budget for wages is reduced, this could mean it employs fewer workers."}'::jsonb, '{"answer": true, "explain": "Correct. The budget available is a key factor in HR planning. If other costs rise and the wage budget falls, the business may need to hire fewer workers or shift to part-time/zero-hours contracts to manage the cost."}'::jsonb),
('business:3-1-role-of-human-resources:tf:f4478620', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tf', 'tf', 1, '{"question": "Milnedale Outdoors planned to increase its sales staff numbers from Year 1 to Year 2."}'::jsonb, '{"answer": true, "explain": "Correct. Penny planned 2 sales staff per day in Year 1, rising to 3 per day in Years 2 and 3. This explains why the sales staff cost rises from £84,000 in Year 1 to £134,400 in Year 2."}'::jsonb),
('business:3-1-role-of-human-resources:tf:7b5887a3', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tf', 'tf', 1, '{"question": "Researching new products is a function of the HR department."}'::jsonb, '{"answer": false, "explain": "Researching new products is a marketing or production function. The HR department focuses on people management: organisation, communications, recruitment, motivation, training, and employment law."}'::jsonb),
('business:3-1-role-of-human-resources:tf:d8d74186', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tf', 'tf', 1, '{"question": "Changes in employment law can affect how many workers a business can afford to employ."}'::jsonb, '{"answer": true, "explain": "Correct. If the government raises the minimum wage, businesses face higher wage costs for the same number of workers. Some may respond by reducing staff numbers or hours, or increasing prices to maintain margins."}'::jsonb),
('business:3-1-role-of-human-resources:tf:1b7f098d', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tf', 'tf', 1, '{"question": "HR planning is always a waste of time and money because business conditions change too quickly."}'::jsonb, '{"answer": false, "explain": "This is too extreme. While HR plans can become outdated, the process of planning helps businesses anticipate changes, have the right workers in place, and avoid costly over-staffing or under-staffing. The benefits generally outweigh the costs."}'::jsonb),
('business:3-1-role-of-human-resources:tf:5a60f85f', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tf', 'tf', 1, '{"question": "Leclerc''s introduction of electronic price tags means it needs more IT staff at head office."}'::jsonb, '{"answer": true, "explain": "Correct. Previously, individual store workers printed and inserted paper tags. Now, an IT specialist at head office can change all prices electronically. This creates demand for more skilled IT workers at the centre."}'::jsonb),
('business:3-1-role-of-human-resources:tf:e3ea8f8f', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tf', 'tf', 1, '{"question": "The interdependent nature of business means that HR decisions never affect other departments."}'::jsonb, '{"answer": false, "explain": "The interdependent nature of business means decisions in one area ALWAYS affect other areas. For example, a finance decision to cut the wage budget directly affects how many workers HR can recruit — and that affects production capacity."}'::jsonb),
('business:3-1-role-of-human-resources:learn:3705b3d7', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'learn', 'mcq', 1, '{"readingTitle": "Core Terminology", "reading": "<ul>\n<li><strong>Human resources (HR)</strong> — the people who do the work for a business; includes owners who work in the business, employees, and contractors</li>\n<li><strong>Human resources department</strong> — the functional area responsible for coordinating all staff-related issues within a business</li>\n<li><strong>Functions</strong> — different types of work that need to be done in a business, e.g. production, finance, marketing</li>\n<li><strong>Human resource plan</strong> — a plan detailing the workers a business needs: how many, full- or part-time, the skills required, and when they will work</li>\n<li><strong>Identifying HR needs</strong> — the activity of thinking about the purposes of human resources and deciding how many and what types of workers will be needed</li>\n<li><strong>Regulations</strong> — rules imposed on businesses by the government that affect how they employ and manage workers</li>\n<li><strong>Zero-hours contracts</strong> — contracts given to employees which do not guarantee any work; the business calls workers in as and when needed</li>\n</ul>", "question": "What is the defining feature of a zero-hours contract?", "options": ["It guarantees at least 8 hours per week", "It only guarantees weekend hours", "It never guarantees any hours of work", "It guarantees full-time hours"]}'::jsonb, '{"answer": 2, "explain": "A zero-hours contract does not guarantee any work — the business calls workers in as and when needed, as defined in the Core Terminology card."}'::jsonb),
('business:3-1-role-of-human-resources:learn:cbc6869e', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'learn', 'mcq', 1, '{"readingTitle": "The Purpose of Human Resources", "reading": "<p>The purpose of human resources is to carry out the <strong>functions</strong> of a business:</p>\n<ul>\n<li><strong>Production workers</strong> — make the product or provide the service</li>\n<li><strong>Finance workers</strong> — send out bills and collect payments</li>\n<li><strong>Marketing workers</strong> — make decisions about what to sell, where to sell it, how to promote it, and what price to charge</li>\n</ul>\n<p>The HR department specifically deals with:</p>\n<ul>\n<li>The organisation of workers (Unit 3.2)</li>\n<li>Communications in the workplace (Unit 3.3)</li>\n<li>Recruitment and selection of workers (Unit 3.4)</li>\n<li>Motivation and retention of workers (Unit 3.5)</li>\n<li>Training and development of workers (Unit 3.6)</li>\n<li>Employment law (Unit 3.7)</li>\n</ul>\n<p><strong>Case Study — Virgin:</strong> Virgin has a habit of listening to employees, showing they are valued, taking care of their ideas, and continuously innovating. Employee engagement is described as the fuel of the organisation.</p>", "question": "Which of these is specifically a responsibility of the HR department, rather than another business function?", "options": ["Deciding what price to charge for products", "Training and development of workers", "Sending out bills and collecting payments", "Deciding what to sell and where to sell it"]}'::jsonb, '{"answer": 1, "explain": "The HR department deals with training and development, recruitment, motivation, communications, and employment law — pricing and sales decisions belong to marketing, not HR."}'::jsonb),
('business:3-1-role-of-human-resources:learn:55fbbff3', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'learn', 'mcq', 1, '{"readingTitle": "Identifying Human Resource Needs", "reading": "<p>Well-run businesses think about their HR needs <strong>regularly</strong> to predict changes that might affect the business. If good predictions are made, the business will be better able to recruit the right workers and remain efficient and competitive.</p>\n<p><strong>Things to consider when planning HR needs:</strong></p>\n<ul>\n<li>The number of workers needed</li>\n<li>Full-time vs part-time workers</li>\n<li>Whether to use zero-hours contracts</li>\n<li>How many workers to hire as contractors</li>\n<li>When workers will be needed (times of day, days of week)</li>\n<li>Where workers will work</li>\n<li>The skills workers will need</li>\n<li>The need to manage and supervise workers</li>\n<li>Age, gender or ethnicity requirements (within employment law)</li>\n<li>How many staff the business can afford to employ</li>\n</ul>", "question": "How often should well-run businesses think about their HR needs, according to good HR planning practice?", "options": ["Only once, when the business first starts up", "Regularly, to predict business changes ahead", "Only when a worker resigns", "Only once every ten years"]}'::jsonb, '{"answer": 1, "explain": "The card states that well-run businesses think about HR needs regularly to predict changes and remain efficient and competitive."}'::jsonb),
('business:3-1-role-of-human-resources:learn:6eb923f5', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'learn', 'mcq', 1, '{"readingTitle": "Why HR Needs Change Over Time", "reading": "<p>Businesses must review their HR needs regularly because many things can cause them to change:</p>\n<ul>\n<li><strong>Worker turnover</strong> — workers may retire, leave for other jobs, or be promoted, requiring replacements</li>\n<li><strong>Business growth or decline</strong> — changes in economic growth or competition affect demand, meaning more or fewer workers are needed</li>\n<li><strong>Changes in production method</strong> — switching from job to batch production, or introducing new technology, may require workers with different or more specialised skills</li>\n<li><strong>Relocation</strong> — the business may need to recruit locally at the new site and may wish to transfer some existing workers</li>\n<li><strong>Budget changes</strong> — reduced budgets (if other costs rise) or increased budgets (if prices rise) affect how many workers can be employed</li>\n<li><strong>Changes in the law</strong> — new regulations may change minimum pay levels or the rules around employing workers</li>\n</ul>\n<p>These changes are examples of the <strong>interdependent nature of business</strong> — decisions in one area affect another.</p>", "question": "What term describes the idea that a decision in one area of a business, such as production method, affects another area, such as HR needs?", "options": ["Delayering", "Economies of scale", "Interdependence", "Business diversification"]}'::jsonb, '{"answer": 2, "explain": "The card explicitly labels these knock-on effects as examples of the interdependent nature of business."}'::jsonb),
('business:3-1-role-of-human-resources:learn:64fd4066', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'learn', 'mcq', 1, '{"readingTitle": "Factors That Influence HR Needs", "reading": "<p>Several business factors determine what kind of human resources a business needs:</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">Factor</div>\n<div class=\"pro-item\"><strong>What it produces</strong> — Are skilled or unskilled workers needed, or a mix?</div>\n<div class=\"pro-item\"><strong>How much it produces</strong> — How many workers will the business need?</div>\n<div class=\"pro-item\"><strong>Method of production</strong> — Can machines replace workers, or are people essential?</div>\n</div>\n<div>\n<div class=\"col-head\">Factor</div>\n<div class=\"pro-item\"><strong>When production takes place</strong> — Are workers needed seven days a week or only at specific times?</div>\n<div class=\"pro-item\"><strong>Functions to be completed</strong> — Finance, production, marketing, HR roles?</div>\n<div class=\"pro-item\"><strong>Budget available</strong> — How much can the business afford to spend on workers?</div>\n</div>\n</div>", "question": "Which factor affecting HR needs is concerned with whether machines can replace workers or whether people are essential?", "options": ["Budget available", "Functions to be completed", "What it produces", "Method of production"]}'::jsonb, '{"answer": 3, "explain": "The ''method of production'' factor specifically asks whether machines can replace workers or people are essential, as listed in the Factors That Influence HR Needs card."}'::jsonb),
('business:3-1-role-of-human-resources:learn:dffd9102', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'learn', 'mcq', 1, '{"readingTitle": "Benefits and Costs of HR Planning", "reading": "<p><strong>Benefits of identifying HR needs:</strong></p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Benefits</div>\n<div class=\"pro-item\">Helps recruit the right workers with the right skills at the right time</div>\n<div class=\"pro-item\">Allows the business to operate efficiently and remain competitive</div>\n<div class=\"pro-item\">Reduces costly over-staffing or damaging under-staffing</div>\n<div class=\"pro-item\">Helps the business survive and make good profits in the long run</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Costs / Risks</div>\n<div class=\"con-item\">Takes time — managers must spend working hours on planning rather than other tasks</div>\n<div class=\"con-item\">Costs money to carry out — time has an opportunity cost</div>\n<div class=\"con-item\">Forecasts may be inaccurate if the market changes unexpectedly</div>\n<div class=\"con-item\">Planning too far ahead may be wasted if circumstances change rapidly</div>\n</div>\n</div>\n<p style=\"margin-top:10px;\"><strong>Evaluation:</strong> Despite the costs, HR planning is generally worth the investment because without it, a business risks having the wrong number of workers with the wrong skills — leading to inefficiency, poor customer service, and lost profit.</p>", "question": "Which of these is identified as a cost/risk of HR planning in the evaluation?", "options": ["Market shifts can make forecasts inaccurate", "It guarantees higher profits every year", "It always causes overstaffing", "It removes the need for recruitment"]}'::jsonb, '{"answer": 0, "explain": "The card lists inaccurate forecasts (if the market changes unexpectedly) as one of the costs/risks of HR planning, alongside the time and opportunity cost involved."}'::jsonb),
('business:3-1-role-of-human-resources:learn:b6706c6b', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'learn', 'mcq', 1, '{"readingTitle": "Case Studies: Milnedale Outdoors & Leclerc", "reading": "<p><strong>Milnedale Outdoors (Penny George):</strong> A fictional outdoor sports clothing retailer. Penny produced an HR plan as part of her business plan for a bank loan. Key details:</p>\n<ul>\n<li>Penny herself: 5 days/week including weekends — responsible for sales, marketing, and purchasing stock</li>\n<li>Sales staff: 2 per day in year 1, rising to 3 in years 2 and 3; covering all 7 days</li>\n<li>Stock assistant: 3 days per week across all three years</li>\n<li>Total payroll: Year 1 = £152,400; Year 2 = £208,400; Year 3 = £212,600</li>\n</ul>\n<p><strong>Leclerc (French supermarket chain):</strong> Introduced electronic price tags replacing paper labels. HR implications:</p>\n<ul>\n<li>Fewer store workers needed to print and change paper price labels</li>\n<li>More IT specialists needed at head office to manage the pricing system</li>\n<li>HR department needed to manage redundancies sensitively and recruit new IT staff</li>\n<li>Potential cost savings from lower total wage bill if fewer store staff are needed</li>\n</ul>", "question": "In the Leclerc case study, what does the introduction of electronic price tags illustrate about the effect of new technology on HR needs?", "options": ["It always increases the total number of workers needed", "It cuts store roles but raises need for IT roles", "It has no effect on staffing at all", "It only affects head office staff, never store staff"]}'::jsonb, '{"answer": 1, "explain": "Leclerc needed fewer store workers to change paper price labels but more IT specialists at head office to manage the electronic pricing system."}'::jsonb),
('business:3-1-role-of-human-resources:misc:94128e09', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Human resources only refers to the HR department of a business.</p><p><strong>✅ The correct idea:</strong> Human resources refers to ALL the people who do work for a business — including the owner, all employees, and contractors. The HR department is just one part of the business that manages those people. A small business with no HR department still has human resources.</p>", "question": "Which of these best describes ''human resources''?", "options": ["Only the staff who work in the HR department", "Only the managers of a business", "All the people who work for the business", "Only employees who are on permanent contracts"]}'::jsonb, '{"answer": 2, "explain": "Human resources means ALL the people who do work for a business — the HR department is just the part of the business that manages those people."}'::jsonb),
('business:3-1-role-of-human-resources:misc:16ffae50', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> HR needs analysis only needs to be done when a business first starts up.</p><p><strong>✅ The correct idea:</strong> Businesses should review their HR needs REGULARLY — not just at start-up. This is because staffing needs change as businesses grow, introduce new technology, face changes in the law, or when workers leave. Only reviewing at start-up means the business may become over- or under-staffed over time.</p>", "question": "How often should a business carry out HR needs analysis?", "options": ["Only once, when it first starts up", "Regularly, throughout the life of the business", "Only when profits fall", "Only at the very end of the financial year"]}'::jsonb, '{"answer": 1, "explain": "Businesses should review their HR needs regularly, not just at start-up, because staffing needs change as the business grows or conditions change."}'::jsonb),
('business:3-1-role-of-human-resources:misc:577598fe', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Zero-hours workers have no employment rights because they are not guaranteed hours.</p><p><strong>✅ The correct idea:</strong> Zero-hours workers DO have employment rights. They must be paid at least the national minimum wage for any hours they work, they cannot be discriminated against, and they cannot be penalised for not being available to work. Lack of guaranteed hours does not remove their legal rights when they ARE working.</p>", "question": "Which statement about zero-hours contract workers is correct?", "options": ["They cannot ever be paid the national minimum wage", "They have no employment rights at all", "They must be paid minimum wage for hours worked", "They are automatically classed as self-employed"]}'::jsonb, '{"answer": 2, "explain": "Zero-hours workers do have employment rights, including being paid at least the national minimum wage for the hours they actually work."}'::jsonb),
('business:3-1-role-of-human-resources:misc:1354b8eb', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The HR department is only responsible for hiring and firing workers.</p><p><strong>✅ The correct idea:</strong> The HR department has a much wider role: it deals with the organisation of workers, workplace communications, recruitment AND selection, motivation and retention, training and development, and employment law compliance. Hiring and firing is just one part of its responsibilities.</p>", "question": "Besides recruitment and selection, which of these is also a responsibility of the HR department?", "options": ["Deciding the price of products", "Motivation and staff training", "Managing the business''s bank loans", "Researching new product ideas"]}'::jsonb, '{"answer": 1, "explain": "The HR department''s role is much wider than hiring and firing — it also covers motivation, retention, training, development, communications, and employment law."}'::jsonb),
('business:3-1-role-of-human-resources:misc:3a44f40b', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> If a business introduces robots, it will always need fewer workers.</p><p><strong>✅ The correct idea:</strong> Introducing robots usually reduces the need for UNSKILLED workers but INCREASES demand for SKILLED workers (e.g. engineers and programmers to maintain and operate the technology). The total number of workers may fall, but the TYPE of worker needed changes significantly. This is a change in the NATURE of HR needs, not just the number.</p>", "question": "What is the most accurate description of how introducing robots affects HR needs?", "options": ["It has no effect on the type of worker required", "It always reduces the total number of workers needed", "It cuts unskilled jobs but raises need for engineers", "It only affects the finance department"]}'::jsonb, '{"answer": 2, "explain": "Robots typically reduce the need for unskilled workers while increasing demand for skilled workers who can program and maintain the equipment — a change in the nature of HR needs, not simply the number."}'::jsonb),
('business:3-1-role-of-human-resources:misc:d4fb5651', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> HR planning is too expensive and time-consuming to be worthwhile.</p><p><strong>✅ The correct idea:</strong> While HR planning does have a cost (time and money), the BENEFITS usually outweigh these costs. Without planning, a business may recruit too many workers (wasting wages) or too few (failing to meet demand). Good HR planning helps the business be efficient and competitive — it is time and money well spent.</p>", "question": "What is the correct conclusion about whether HR planning is worth the cost?", "options": ["It should only be carried out by large businesses", "It is always too expensive and time-consuming to be worthwhile", "It has no costs at all", "It costs time and money, but benefits usually win"]}'::jsonb, '{"answer": 3, "explain": "The card concludes that although HR planning has a cost, the benefits generally outweigh this cost because it helps a business avoid recruiting too many or too few workers."}'::jsonb),
('business:3-1-role-of-human-resources:tips:c529b6cd', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tips', 'mcq', 1, '{"readingTitle": "Most Repeated Question Type — Analyse one way HR needs may change (3 marks)", "reading": "Structure: (U) Explain the type of change — e.g. ''fewer workers may be needed.'' (APP) Link to the specific business in the case study — e.g. ''workers who print price labels at Leclerc will no longer be needed.'' (AN) Show the business impact — e.g. ''this may reduce Leclerc''s wage bill, increasing profit.'' Always chain: change → effect on THIS business → business consequence.", "question": "For a 3-mark ''analyse one way HR needs may change'' question, what should follow stating the type of change?", "options": ["A personal opinion about whether the change is fair", "Link the change to the business, then show its impact", "A list of as many possible changes as can be thought of", "Repeating the question in different words"]}'::jsonb, '{"answer": 1, "explain": "The recommended structure is to chain: change → effect on THIS business (using case study detail) → business consequence, as shown in the Leclerc price-tag example."}'::jsonb),
('business:3-1-role-of-human-resources:tips:d7603c52', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tips', 'mcq', 1, '{"readingTitle": "Most Repeated Question Type — Evaluate the importance of the HR department (3 marks)", "reading": "Make a clear judgement (1 mark): ''The HR department is very important to [business].'' Then justify with TWO contextual reasons linked to the case study (2 marks). Example: ''Leclerc needs its HR department to manage redundancies sensitively so it keeps its good reputation for treating staff fairly, AND to recruit the IT specialists needed to manage the new pricing system.''", "question": "How are marks awarded for a 3-mark question evaluating the importance of the HR department?", "options": ["3 marks for listing three separate HR functions", "1 mark for spelling key terms correctly", "A judgement mark plus two case-linked reasons", "3 marks purely for the length of the answer"]}'::jsonb, '{"answer": 2, "explain": "The mark scheme awards 1 mark for a clear judgement and 2 further marks for two reasons justified with context from the case study."}'::jsonb),
('business:3-1-role-of-human-resources:tips:f5f40324', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tips', 'mcq', 1, '{"readingTitle": "Most Repeated Question Type — State/identify one factor that affects HR needs (1 mark)", "reading": "Short questions: name ONE factor clearly — e.g. ''the method of production,'' ''the budget available,'' ''changes in the law,'' ''whether the business is growing.'' Do not just write ''the business changes'' — be specific about WHICH factor. One well-chosen word can earn a mark here.", "question": "For a 1-mark question asking students to state one factor that affects HR needs, what earns the mark?", "options": ["Explaining the factor in full detail with examples", "Naming one clear factor, like the available budget", "Listing as many factors as possible", "Writing a vague statement like ''the business changes''"]}'::jsonb, '{"answer": 1, "explain": "The card warns that a vague answer like ''the business changes'' will not score — students must name ONE specific factor clearly."}'::jsonb),
('business:3-1-role-of-human-resources:tips:e1bd89f8', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tips', 'mcq', 1, '{"readingTitle": "Calculation Questions — Workforce planning calculations", "reading": "Common calculation: how many workers are needed? Formula: Total units ÷ (hours available × units per hour per worker) = workers needed. Example: 7,200 T-shirts ÷ (120 hours × 20 T-shirts/hour) = 7,200 ÷ 2,400 = 3 workers. Always show your working step by step — a correct method with a wrong answer can still earn method marks.", "question": "What is the correct formula for calculating how many workers are needed to complete a production order?", "options": ["Hours available ÷ total units", "Total units ÷ number of days available", "Total units × hours available ÷ units per hour", "Total units divided by hours times output per hour"]}'::jsonb, '{"answer": 3, "explain": "The card''s worked example divides total units (7,200 T-shirts) by hours available multiplied by units per hour per worker (120 × 20 = 2,400) to get workers needed."}'::jsonb),
('business:3-1-role-of-human-resources:tips:d4625cbe', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tips', 'mcq', 1, '{"readingTitle": "9-Mark Evaluate Question — Evaluate the impact of a change on HR needs", "reading": "Structure for 9-mark questions: K (define HR or HR needs) → U (explain the specific HR change) → APP x2 (use numbers or details from the case study twice) → AN x2 (show the business impact of each change) → EVAL x3 (overall judgement: is the change positive or negative for the business? Justify with context). Always reach a conclusion.", "question": "What structure should be used to answer a 9-mark question evaluating the impact of a change on HR needs?", "options": ["A single unstructured paragraph giving an opinion", "K, U, APP x2, AN x2, EVAL x3, ending with a conclusion", "A list of bullet points with no explanation", "A definition only, with no application or evaluation"]}'::jsonb, '{"answer": 1, "explain": "The card sets out the structure as K (define) → U (explain) → APP x2 → AN x2 → EVAL x3, always reaching a conclusion."}'::jsonb),
('business:3-1-role-of-human-resources:tips:e981b0cb', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tips', 'mcq', 1, '{"readingTitle": "Examiner Warning — Always link HR changes to business consequences", "reading": "Students often stop at identifying the HR change (e.g. ''fewer workers needed'') without explaining the business consequence. Examiners award analysis marks for explaining the IMPACT: ''fewer workers needed → lower wage bill → higher profit → more competitive pricing.'' Never describe without analysing the effect on the business.", "question": "What mistake do examiners commonly penalise when students answer HR change questions?", "options": ["Making a clear judgement at the end of the answer", "Using specific details from the case study", "Naming the HR change without its business consequence", "Writing in full sentences"]}'::jsonb, '{"answer": 2, "explain": "The Examiner Warning states that students often lose analysis marks by identifying a change (e.g. fewer workers needed) without explaining its impact on the business."}'::jsonb),
('business:3-1-role-of-human-resources:tips:4bfcf63d', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tips', 'mcq', 1, '{"readingTitle": "Key Examiner Warning — Do not confuse ''HR department'' with ''human resources''", "reading": "Examiners regularly penalise students who say ''the business has no HR department therefore it has no human resources.'' Every business has human resources — its workers. The HR department is just the function that manages them. Small businesses can have human resources without having a dedicated HR team.", "question": "Why is it incorrect to say ''a business with no HR department has no human resources''?", "options": ["Because HR departments are legally compulsory for every business", "Because human resources only exist in large businesses", "Because the HR department creates human resources rather than manages them", "Every business has workers — HR just manages people"]}'::jsonb, '{"answer": 3, "explain": "The card warns that examiners penalise this confusion: human resources are the workers themselves, while the HR department is only the function managing them, so small businesses can have human resources without a dedicated HR team."}'::jsonb),
('business:3-1-role-of-human-resources:tips:4a40a078', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'tips', 'mcq', 1, '{"readingTitle": "Evaluation Tip — Both costs AND benefits of HR planning", "reading": "If asked to evaluate whether HR planning is worthwhile, always present BOTH sides: Benefits (right workers at right time, efficient operations, competitive advantage) vs Costs (time-consuming, expensive, forecasts may be wrong). Conclude with a justified overall judgement — e.g. ''the benefits outweigh the costs because accurate planning means the business is less likely to waste money on unnecessary staff.''", "question": "When evaluating whether HR planning is worthwhile, what should a strong answer include?", "options": ["Only the benefits, since HR planning is always worthwhile", "Both benefits and costs, then a justified judgement", "A list of definitions with no judgement", "Only the costs, since HR planning is rarely worthwhile"]}'::jsonb, '{"answer": 1, "explain": "The Evaluation Tip advises presenting both benefits and costs of HR planning before reaching a justified overall conclusion."}'::jsonb),
('business:3-1-role-of-human-resources:fib:e7ac164b', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'fib', 'fib', 2, '{"question": "Businesses must identify their human resource needs when they _____ up. The purpose of identifying HR needs is to decide what kind of staff and how _____ workers to employ.", "blankOptions": {"B1": ["start", "full", "promoted", "skilled"], "B2": ["many", "training", "recruitment", "motivated"]}}'::jsonb, '{"blanks": {"B1": "start", "B2": "many"}}'::jsonb),
('business:3-1-role-of-human-resources:fib:ef1e479a', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'fib', 'fib', 2, '{"question": "Well-run businesses look at their staffing needs _____ to see if they are changing, for example because the business is _____ or changing the way it produces goods.", "blankOptions": {"B1": ["skilled", "many", "regularly", "increase"], "B2": ["reduced", "needed", "growing", "dismissed"]}}'::jsonb, '{"blanks": {"B1": "regularly", "B2": "growing"}}'::jsonb),
('business:3-1-role-of-human-resources:fib:96c9de19', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'fib', 'fib', 2, '{"question": "A worker on a _____ contract is not guaranteed any hours. The business will contact them if and when they are _____.", "blankOptions": {"B1": ["growing", "promoted", "skilled", "zero-hours"], "B2": ["needed", "growing", "training", "fewer"]}}'::jsonb, '{"blanks": {"B1": "zero-hours", "B2": "needed"}}'::jsonb),
('business:3-1-role-of-human-resources:fib:b65fe7d8', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'fib', 'fib', 2, '{"question": "The HR department is responsible for the _____ and selection of workers, their _____ and development, and ensuring the business complies with employment law.", "blankOptions": {"B1": ["recruitment", "dismissed", "start", "reduced"], "B2": ["promoted", "part", "growing", "training"]}}'::jsonb, '{"blanks": {"B1": "recruitment", "B2": "training"}}'::jsonb),
